#!/usr/bin/env bash
set -Eeuo pipefail

# Homelab Bacmaster's AI Open WebUI theme - v4 logo/corner polish
# Usage:
#   bash apply-bacmasters-ai-openwebui-theme-v4-polish.sh apply
#   bash apply-bacmasters-ai-openwebui-theme-v4-polish.sh status
#   bash apply-bacmasters-ai-openwebui-theme-v4-polish.sh restore

MODE="${1:-apply}"
if [[ "${MODE:-}" == "--inside-vm" ]]; then INSIDE_VM=1; MODE="${2:-apply}"; else INSIDE_VM=0; fi
DEFAULT_VM_IP="192.168.50.106"
DEFAULT_CONTAINER="hb-openwebui"
REMOTE_PATH="/tmp/apply-bacmasters-ai-openwebui-theme-v4-polish.sh"
BRAND_DIR="/opt/homelab/branding/bacmasters-ai"

log(){ printf '\n==> %s\n' "$*"; }
ok(){ printf '✅ %s\n' "$*"; }
warn(){ printf '⚠️  %s\n' "$*"; }
err(){ printf '❌ %s\n' "$*" >&2; }
need(){ command -v "$1" >/dev/null 2>&1 || { err "Gerekli komut yok: $1"; exit 1; }; }
self_path(){ local p="${BASH_SOURCE[0]:-$0}"; [[ -f "$p" ]] || { err "Script dosya olarak çalıştırılmalı."; exit 1; }; cd "$(dirname "$p")" && printf '%s/%s\n' "$PWD" "$(basename "$p")"; }

extract_payload(){
  local dest="$1" self
  self="$(self_path)"
  mkdir -p "$dest/payload"
  awk '/^__BACAI_V2_PAYLOAD_START__$/ {f=1; next} /^__BACAI_V2_PAYLOAD_END__$/ {f=0} f {print}' "$self" | base64 -d | tar -xz -C "$dest/payload"
}

find_container(){
  local c="${OPENWEBUI_CONTAINER:-}"
  if [[ -n "$c" ]] && docker inspect "$c" >/dev/null 2>&1; then echo "$c"; return 0; fi
  for c in "$DEFAULT_CONTAINER" open-webui openwebui open_webui hb-ollama-openwebui; do
    if docker inspect "$c" >/dev/null 2>&1; then echo "$c"; return 0; fi
  done
  docker ps -a --format '{{.Names}}' | grep -Eim1 '(^|[-_])(open[-_]?webui|openwebui)([-_]|$)|webui' || true
}

container_running(){ [[ "$(docker inspect -f '{{.State.Running}}' "$1" 2>/dev/null || true)" == "true" ]]; }

find_web_root(){
  local c="$1"
  docker exec "$c" sh -lc '
    for d in /app/build /app/build/client /app/frontend/dist /app/dist /usr/share/nginx/html /app/backend/static /app/public /build/www; do
      if [ -f "$d/index.html" ]; then echo "$d"; exit 0; fi
    done
    find /app /usr/share/nginx /build /opt -maxdepth 6 -type f -name index.html 2>/dev/null | head -n1 | sed "s#/index.html$##"
  ' | head -n1
}

compose_cmd(){ if docker compose version >/dev/null 2>&1; then echo "docker compose"; elif command -v docker-compose >/dev/null 2>&1; then echo "docker-compose"; else return 1; fi; }
compose_info(){
  local c="$1"
  printf '%s\t%s\t%s\n' \
    "$(docker inspect -f '{{ index .Config.Labels "com.docker.compose.project.working_dir" }}' "$c" 2>/dev/null || true)" \
    "$(docker inspect -f '{{ index .Config.Labels "com.docker.compose.project.config_files" }}' "$c" 2>/dev/null || true)" \
    "$(docker inspect -f '{{ index .Config.Labels "com.docker.compose.service" }}' "$c" 2>/dev/null || true)"
}

write_compose_override(){
  local c="$1" info workdir cfg service override dc
  info="$(compose_info "$c")"
  workdir="$(printf '%s' "$info" | awk -F'\t' '{print $1}')"
  cfg="$(printf '%s' "$info" | awk -F'\t' '{print $2}')"; cfg="${cfg%%,*}"
  service="$(printf '%s' "$info" | awk -F'\t' '{print $3}')"
  if [[ -z "$workdir" || "$workdir" == "<no value>" || -z "$cfg" || "$cfg" == "<no value>" || -z "$service" || "$service" == "<no value>" ]]; then
    warn "Compose etiketi bulunamadı; env override atlandı ama FORCE tema uygulanacak."
    return 0
  fi
  [[ "$cfg" = /* ]] || cfg="$workdir/$cfg"
  [[ -f "$cfg" ]] || { warn "Compose dosyası bulunamadı: $cfg"; return 0; }
  override="$workdir/docker-compose.bacmasters-ai.override.yml"
  mkdir -p "$workdir/.bacmasters-ai-backups"
  [[ -f "$override" ]] && cp -a "$override" "$workdir/.bacmasters-ai-backups/$(basename "$override").$(date +%Y%m%d-%H%M%S).bak"
  cat > "$override" <<EOF_OVERRIDE
# Generated by Homelab Bacmaster's AI branding v4 logo/corner polish.
services:
  $service:
    environment:
      WEBUI_NAME: "Bacmaster's AI"
      CUSTOM_NAME: "Bacmaster's AI"
EOF_OVERRIDE
  ok "Compose override yazıldı: $override"
  if dc="$(compose_cmd)"; then
    log "Open WebUI env için yeniden oluşturuluyor"
    ( cd "$workdir" && $dc -f "$cfg" -f "$override" up -d --force-recreate "$service" ) || warn "Compose recreate başarısız; container patch ile devam."
    sleep 5
  fi
}

patch_auth_redirect_chunks(){
  local c="$1" root="$2" dir="$3" stamp="$4"
  log "Auth redirect JS chunk patch uygulanıyor"
  if ! docker exec -i "$c" sh -lc "python3 - '$root' '$stamp'" <<'PY_CHUNK'
from pathlib import Path
import sys
root=Path(sys.argv[1]); stamp=sys.argv[2]
backup=root/'bacmasters-ai'/'chunk-backups'/stamp
changed=0
scanned=0
patterns=(('/auth?redirect=', '/auth#redirect='),('/auth?redirect%3D', '/auth#redirect%3D'))
for p in list(root.rglob('*.js')):
    if 'bacmasters-ai' in p.parts:
        continue
    try:
        if p.stat().st_size > 15_000_000:
            continue
        txt=p.read_text(encoding='utf-8', errors='ignore')
    except Exception:
        continue
    scanned += 1
    new=txt
    for a,b in patterns:
        new=new.replace(a,b)
    if new != txt:
        rel=p.relative_to(root)
        dest=backup/rel
        dest.parent.mkdir(parents=True, exist_ok=True)
        dest.write_text(txt, encoding='utf-8')
        p.write_text(new, encoding='utf-8')
        changed += 1
print(f"scanned_js={scanned} patched_js={changed} backup={backup if changed else '-'}")
PY_CHUNK
  then
    warn "JS chunk patch çalışmadı; index/theme patch yine aktif."
  fi
}

patch_index(){
  local c="$1" root="$2" dir="$3" stamp="$4" backup_dir patched
  backup_dir="$dir/backups/v4-polish-$stamp"
  mkdir -p "$backup_dir"
  docker exec "$c" sh -lc "mkdir -p '$root/bacmasters-ai'"
  docker cp "$dir/payload/logo-wide.png" "$c:$root/bacmasters-ai/logo-wide.png"
  docker cp "$dir/payload/main-logo.png" "$c:$root/bacmasters-ai/main-logo.png"
  docker cp "$dir/payload/favicon.png" "$c:$root/bacmasters-ai/favicon.png"
  docker cp "$dir/payload/bacmasters-ai-force.css" "$c:$root/bacmasters-ai/bacmasters-ai-force.css"
  docker cp "$dir/payload/bacmasters-ai-force.js" "$c:$root/bacmasters-ai/bacmasters-ai-force.js"
  docker cp "$c:$root/index.html" "$backup_dir/index.html.original" || warn "index.html backup alınamadı."
  patched="$backup_dir/index.html.patched"
  cp -f "$backup_dir/index.html.original" "$patched"
  python3 - "$patched" "$dir/payload" "$stamp" <<'PY_PATCH'
from pathlib import Path
import base64, re, sys
p=Path(sys.argv[1]); payload=Path(sys.argv[2]); stamp=sys.argv[3]
html=p.read_text(encoding='utf-8', errors='ignore')
# Eski v1/v2 bloklarını temizle
html=re.sub(r'\n?\s*<!-- BACMASTERS_AI_BRANDING_START -->.*?<!-- BACMASTERS_AI_BRANDING_END -->\s*\n?', '\n', html, flags=re.S)
html=re.sub(r'\n?\s*<!-- BACMASTERS_AI_FORCE_START -->.*?<!-- BACMASTERS_AI_FORCE_END -->\s*\n?', '\n', html, flags=re.S)
# Cache-bust existing app assets so the browser stops using the old auth redirect bundle.
def bust_src(m):
    return f"{m.group(1)}{m.group(2)}?bacai={stamp}{m.group(3)}"
html=re.sub(r'(<script\b[^>]*\bsrc=[\"\'])(?!data:)([^\"\']+\.js)(?:\?[^\"\']*)?([\"\'])', bust_src, html, flags=re.I)
html=re.sub(r'(<link\b[^>]*\bhref=[\"\'])(?!data:)([^\"\']+\.(?:css|ico|png|svg|webmanifest))(?:\?[^\"\']*)?([\"\'])', bust_src, html, flags=re.I)
cache_meta='<meta http-equiv="Cache-Control" content="no-store, no-cache, must-revalidate, max-age=0"><meta http-equiv="Pragma" content="no-cache">'
if 'http-equiv="Cache-Control"' not in html and re.search(r'<head[^>]*>', html, re.I):
    html=re.sub(r'(<head[^>]*>)', r'\1'+cache_meta, html, count=1, flags=re.I)
css=(payload/'bacmasters-ai-force.css').read_text(encoding='utf-8')
js=(payload/'bacmasters-ai-force.js').read_text(encoding='utf-8')
def data(name):
    return 'data:image/png;base64,'+base64.b64encode((payload/name).read_bytes()).decode('ascii')
embedded = f"""
window.BACMASTERS_AI_VERSION = {stamp!r};
window.BACMASTERS_AI_ASSET_BASE = '/bacmasters-ai';
window.BACMASTERS_AI_EMBEDDED = {{
  'logo-wide': {data('logo-wide.png')!r},
  'main-logo': {data('main-logo.png')!r},
  'favicon': {data('favicon.png')!r}
}};
"""
block=f"""
<!-- BACMASTERS_AI_FORCE_START -->
<link rel="icon" type="image/png" href="/bacmasters-ai/favicon.png?v={stamp}">
<link rel="apple-touch-icon" href="/bacmasters-ai/favicon.png?v={stamp}">
<link rel="stylesheet" href="/bacmasters-ai/bacmasters-ai-force.css?v={stamp}">
<style id="bacmasters-ai-force-inline">\n{css}\n</style>
<script id="bacmasters-ai-force-data">\n{embedded}\n</script>
<script defer src="/bacmasters-ai/bacmasters-ai-force.js?v={stamp}"></script>
<script id="bacmasters-ai-force-inline-js">\n{js}\n</script>
<!-- BACMASTERS_AI_FORCE_END -->
"""
if re.search(r'</head\s*>', html, re.I):
    html=re.sub(r'</head\s*>', block+'</head>', html, count=1, flags=re.I)
else:
    html=block+html
if re.search(r'<title>.*?</title>', html, re.I|re.S):
    html=re.sub(r'<title>.*?</title>', "<title>Bacmaster's AI</title>", html, flags=re.I|re.S)
else:
    html=html.replace('<head>', '<head><title>Bacmaster\'s AI</title>', 1)
p.write_text(html, encoding='utf-8')
PY_PATCH
  docker cp "$patched" "$c:$root/index.html"
  ok "FORCE index/theme patch uygulandı: $root"
}

apply_inside_vm(){
  need docker; need base64; need tar; need python3
  local c root dir stamp
  stamp="$(date +%Y%m%d-%H%M%S)"
  dir="$BRAND_DIR"
  log "Open WebUI container aranıyor"
  c="$(find_container)"; [[ -n "$c" ]] || { err "Open WebUI container bulunamadı."; exit 1; }
  ok "Container: $c"
  container_running "$c" || docker start "$c" >/dev/null || true
  log "Payload hazırlanıyor"
  rm -rf "$dir/payload"; mkdir -p "$dir"
  extract_payload "$dir"
  write_compose_override "$c"
  c="$(find_container)"; container_running "$c" || docker start "$c" >/dev/null || true
  log "Web root aranıyor"
  root="$(find_web_root "$c" || true)"; [[ -n "$root" ]] || { err "index.html/web root bulunamadı."; exit 1; }
  ok "Web root: $root"
  patch_index "$c" "$root" "$dir" "$stamp"
  patch_auth_redirect_chunks "$c" "$root" "$dir" "$stamp"
  log "Container yeniden başlatılıyor"
  docker restart "$c" >/dev/null || warn "restart başarısız; manuel kontrol et."
  sleep 4
  if command -v curl >/dev/null 2>&1; then
    echo "HTTP marker test:"
    curl -fsS --max-time 10 "${OPENWEBUI_URL:-http://127.0.0.1:3000}/" | grep -Eo 'BACMASTERS_AI_FORCE_START|bacai-force-logo' | head -n2 || warn "HTTP index marker görünmedi; yine de dosya patchlendi."
    curl -fsSI --max-time 8 "${OPENWEBUI_URL:-http://127.0.0.1:3000}/bacmasters-ai/logo-wide.png" | head -n1 || warn "HTTP asset testi başarısız; inline logo yine de kullanılacak."
  fi
  ok "Bacmaster's AI v4 logo/corner polish uygulandı. Root giriş artık /auth query yerine temalı auth ekranına düşmeli. Ctrl+F5 iyi olur."
}

status_inside_vm(){
  need docker
  local c root
  c="$(find_container)"; [[ -n "$c" ]] || { err "Open WebUI container bulunamadı."; exit 1; }
  echo "Container: $c"
  echo "Running: $(docker inspect -f '{{.State.Running}}' "$c" 2>/dev/null || true)"
  echo "Image: $(docker inspect -f '{{.Config.Image}}' "$c" 2>/dev/null || true)"
  echo "Env:"
  docker inspect -f '{{range .Config.Env}}{{println .}}{{end}}' "$c" 2>/dev/null | grep -E '^(WEBUI_NAME|CUSTOM_NAME)=' || echo "  WEBUI_NAME/CUSTOM_NAME görünmedi."
  root="$(find_web_root "$c" || true)"; echo "Web root: ${root:-bulunamadı}"
  if [[ -n "$root" ]]; then
    echo "Index markers:"
    docker exec "$c" sh -lc "grep -c 'BACMASTERS_AI_FORCE_START' '$root/index.html' 2>/dev/null || true; grep -c 'BACMASTERS_AI_BRANDING_START' '$root/index.html' 2>/dev/null || true" | awk 'NR==1{print "  FORCE=" $0} NR==2{print "  old_v1=" $0}'
    docker exec "$c" sh -lc "ls -lah '$root/bacmasters-ai' 2>/dev/null || true; echo Chunk redirect hits:; grep -Rsl '/auth#redirect=' '$root' --include='*.js' 2>/dev/null | wc -l"
  fi
  if command -v curl >/dev/null 2>&1; then
    echo "HTTP tests:"
    curl -fsS --max-time 8 "${OPENWEBUI_URL:-http://127.0.0.1:3000}/" | grep -Eo 'BACMASTERS_AI_FORCE_START|bacai-force-logo' | head -n3 || true
    curl -fsSI --max-time 8 "${OPENWEBUI_URL:-http://127.0.0.1:3000}/bacmasters-ai/logo-wide.png" | head -n1 || true
  fi
  echo "Host asset dir: $BRAND_DIR"
}

restore_inside_vm(){
  need docker; need python3
  local c root dir latest tmp info workdir cfg service override dc
  dir="$BRAND_DIR"
  c="$(find_container)"; [[ -n "$c" ]] || { err "Open WebUI container bulunamadı."; exit 1; }
  root="$(find_web_root "$c" || true)"
  log "Bacmaster's AI v4 logo/corner polish kaldırılıyor"
  if [[ -n "$root" ]]; then
    latest="$(find "$dir/backups" -mindepth 1 -maxdepth 1 -type d 2>/dev/null | sort | tail -n1 || true)"
    if [[ -n "$latest" && -f "$latest/index.html.original" ]]; then
      docker cp "$latest/index.html.original" "$c:$root/index.html" && ok "index.html son backup'tan geri alındı."
    else
      tmp="/tmp/openwebui-index-restore.$$"; docker cp "$c:$root/index.html" "$tmp" || true
      if [[ -f "$tmp" ]]; then
        python3 - "$tmp" <<'PY_RESTORE'
from pathlib import Path
import re,sys
p=Path(sys.argv[1]); html=p.read_text(encoding='utf-8', errors='ignore')
html=re.sub(r'\n?\s*<!-- BACMASTERS_AI_FORCE_START -->.*?<!-- BACMASTERS_AI_FORCE_END -->\s*\n?', '\n', html, flags=re.S)
html=re.sub(r'\n?\s*<!-- BACMASTERS_AI_BRANDING_START -->.*?<!-- BACMASTERS_AI_BRANDING_END -->\s*\n?', '\n', html, flags=re.S)
p.write_text(html, encoding='utf-8')
PY_RESTORE
        docker cp "$tmp" "$c:$root/index.html" || true; rm -f "$tmp"; ok "index.html marker temizlendi."
      fi
    fi
    if docker exec -i "$c" sh -lc "python3 - '$root'" <<'PY_CHUNK_RESTORE'
from pathlib import Path
import sys, shutil
root=Path(sys.argv[1])
base=root/'bacmasters-ai'/'chunk-backups'
if base.exists():
    backups=sorted([p for p in base.iterdir() if p.is_dir()])
    if backups:
        latest=backups[-1]
        count=0
        for src in latest.rglob('*'):
            if src.is_file():
                rel=src.relative_to(latest)
                dst=root/rel
                dst.parent.mkdir(parents=True, exist_ok=True)
                shutil.copy2(src, dst)
                count+=1
        print(f"restored_js_chunks={count} from={latest}")
PY_CHUNK_RESTORE
    then
      ok "JS chunk redirect patch backup'tan geri alındı."
    else
      warn "JS chunk restore atlandı/başarısız."
    fi
    docker exec "$c" sh -lc "rm -rf '$root/bacmasters-ai'" || true
  fi
  info="$(compose_info "$c")"
  workdir="$(printf '%s' "$info" | awk -F'\t' '{print $1}')"; cfg="$(printf '%s' "$info" | awk -F'\t' '{print $2}')"; cfg="${cfg%%,*}"; service="$(printf '%s' "$info" | awk -F'\t' '{print $3}')"
  if [[ -n "$workdir" && "$workdir" != "<no value>" ]]; then
    override="$workdir/docker-compose.bacmasters-ai.override.yml"
    if [[ -f "$override" ]]; then
      mkdir -p "$workdir/.bacmasters-ai-backups"
      mv "$override" "$workdir/.bacmasters-ai-backups/docker-compose.bacmasters-ai.override.yml.restored.$(date +%Y%m%d-%H%M%S).bak"
      ok "Compose override kaldırıldı."
      [[ "$cfg" = /* ]] || cfg="$workdir/$cfg"
      if [[ -f "$cfg" ]] && dc="$(compose_cmd)"; then ( cd "$workdir" && $dc -f "$cfg" up -d --force-recreate "$service" ) || true; fi
    fi
  fi
  docker restart "$c" >/dev/null || true
  ok "Restore tamamlandı."
}

run_from_proxmox(){
  local mode="$1" vm_ip self vm_user ssh_opts
  vm_ip="${VM106_IP:-${VM_IP:-$DEFAULT_VM_IP}}"
  self="$(self_path)"
  log "Bu makinede Docker/Open WebUI yok; VM106'ya geçiliyor: $vm_ip"
  ssh_opts=(-o StrictHostKeyChecking=accept-new -o UserKnownHostsFile="$HOME/.ssh/known_hosts")
  if [[ -n "${VM_USER:-}" ]]; then vm_user="$VM_USER"; else
    vm_user=""
    for u in root bacmaster homelab; do
      if ssh -o BatchMode=yes -o ConnectTimeout=4 "${ssh_opts[@]}" "$u@$vm_ip" 'true' >/dev/null 2>&1; then vm_user="$u"; break; fi
    done
    vm_user="${vm_user:-bacmaster}"
  fi
  ok "SSH kullanıcı adayı: $vm_user@$vm_ip"
  log "Script VM106'ya kopyalanıyor"
  scp "${ssh_opts[@]}" "$self" "$vm_user@$vm_ip:$REMOTE_PATH"
  log "VM106 üzerinde çalıştırılıyor"
  ssh -tt "${ssh_opts[@]}" "$vm_user@$vm_ip" "if [ \"\$(id -u)\" -eq 0 ]; then bash '$REMOTE_PATH' --inside-vm '$mode'; else sudo bash '$REMOTE_PATH' --inside-vm '$mode'; fi"
}

main(){
  case "$MODE" in apply|status|restore) ;; *) err "Geçersiz mod: $MODE (apply/status/restore)"; exit 1;; esac
  if [[ "$INSIDE_VM" == "1" ]]; then
    case "$MODE" in apply) apply_inside_vm;; status) status_inside_vm;; restore) restore_inside_vm;; esac
  else
    if command -v docker >/dev/null 2>&1 && docker ps >/dev/null 2>&1 && [[ -n "$(find_container)" ]]; then
      case "$MODE" in apply) apply_inside_vm;; status) status_inside_vm;; restore) restore_inside_vm;; esac
    else
      need ssh; need scp; run_from_proxmox "$MODE"
    fi
  fi
}
main "$@"
exit 0

